MERGE INTO RDIUNITPRCMNG_TB U USING(
SELECT #{item.crtr_yr} AS CRTR_YR, #{item.data_cd} AS DATA_CD, #{item.aplcn_ptm_cd} AS APLCN_PTM_CD, #{item.data_se_cd} AS DATA_SE_CD, #{item.aplcn_untprc} AS APLCN_UNTPRC FROM DUAL
) N ON(U.CRTR_YR = N.CRTR_YR AND U.DATA_CD = N.DATA_CD AND U.APLCN_PTM_CD = N.APLCN_PTM_CD AND U.DATA_SE_CD = N.DATA_SE_CD) WHEN MATCHED THEN UPDATE SET APLCN_UNTPRC = N.APLCN_UNTPRC WHEN NOT MATCHED THEN INSERT(CRTR_YR, DATA_CD, APLCN_PTM_CD, DATA_SE_CD, APLCN_UNTPRC) VALUES(N.CRTR_YR, N.DATA_CD, N.APLCN_PTM_CD, N.DATA_SE_CD, N.APLCN_UNTPRC)

